const input = $input.first().json;
const transcript = (input.Transcript || input.transcript || input.text || '').toString().trim();
if (!transcript) { throw new Error('No transcript provided.'); }
const source = (input.Source || input.source || 'manual').toString();

const SYSTEM_PROMPT = [
  'You are a sales-call data extraction assistant for Bell & McCoy Integrated Solutions, a lighting and home-automation manufacturers rep agency serving the luxury home market. Read the transcript and return ONLY one valid JSON object, no markdown. Keys:',
  '- company_name: account/company name, or null',
  '- contact_name: the person name, or null',
  '- summary: 2 to 3 factual sentences, no invented details',
  '- action_items: array of short imperative strings; empty array if none',
  '- order_intent: object with present (boolean), products (array of objects with name and quantity), timeline (string or null), notes (string or null)',
  '- project_name: the project or job the call is about, or null',
  '- customer_type: caller role, one of: architect, designer, builder, home automation integrator, window treatment, landscape, contractor, homeowner, other',
  '- product_category: best-fit line, one of: lighting control, automated shading, LED and architectural lighting, landscape lighting, outdoor audio, whole-home surge, outdoor living, other',
  '- territory_state: the US state the project is in (2-letter code), or null',
  '- priority: high, medium, or low (high when there is a tight deadline or the deal is being pushed)',
  '- risk_flags: array using ONLY these values: pricing_objection, late_delivery_complaint, competitor_mentioned, timeline_risk, spec_change; empty array if none',
  '- missing_or_ambiguous: array of field names you could not confidently fill',
  '- confidence: one of high, medium, low',
  '- needs_human_review: boolean',
  '',
  'Rules:',
  '- Never invent facts. If a value is not clearly stated, use null (or empty array, or present false) and add the field name to missing_or_ambiguous.',
  '- If the caller references a previous deal instead of specifics (for example same as the school job, or do what you did before), do not guess products: set order_intent.present true, leave products empty, and explain the reference in notes and in missing_or_ambiguous.',
  '- Record pricing objections, deadlines and callback requests as action_items.',
  '- Add a risk flag only when clearly supported by the transcript.',
  '- For customer_type and product_category pick the closest option; if unclear use other.',
  '- Set needs_human_review true and confidence low whenever company_name or contact_name is missing, or products or quantities are implied but unknown.',
  'Return only the JSON object.'
].join('\n');

const body = {
  model: 'gpt-4o-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: SYSTEM_PROMPT },
    { role: 'user', content: 'Transcript:\n\n' + transcript }
  ]
};

return [{ json: { transcript, source, received_at: new Date().toISOString(), body } }];

const raw = $input.first().json;
let content = '';
try { content = raw.choices[0].message.content; } catch (e) { content = ''; }
content = (content || '').replace(/```json/gi, '').replace(/```/g, '').trim();

let data; let parseError = false;
try { data = JSON.parse(content); } catch (e) { data = {}; parseError = true; }

const norm = $('Normalize & Build Request').first().json;

const missing = Array.isArray(data.missing_or_ambiguous) ? data.missing_or_ambiguous.slice() : [];
if (!data.company_name && missing.indexOf('company_name') === -1) missing.push('company_name');
if (!data.contact_name && missing.indexOf('contact_name') === -1) missing.push('contact_name');

const confidence = data.confidence || (parseError ? 'low' : 'medium');
const needsReview = parseError || data.needs_human_review === true || missing.length > 0 || confidence === 'low';

const items = Array.isArray(data.action_items) ? data.action_items : [];
const products = (data.order_intent && Array.isArray(data.order_intent.products)) ? data.order_intent.products : [];
const risks = Array.isArray(data.risk_flags) ? data.risk_flags : [];

const preview = [(needsReview ? 'NEEDS REVIEW' : 'Looks complete'), 'Company: ' + (data.company_name || '(missing)'), 'Contact: ' + (data.contact_name || '(missing)')].join('\n');

const esc = s => (s == null ? '' : String(s));
const oi = data.order_intent || {};
const row = (k, v) => '<b>' + k + ':</b> ' + v + '<br>';
const bannerHtml = needsReview
  ? '<h3>⚠️ NEEDS REVIEW</h3>' + (missing.length ? ('<p><b>Missing / ambiguous:</b> ' + missing.join(', ') + '</p>') : '')
  : '<h3>✅ Looks complete</h3>';
const risksHtml = risks.length ? ('<p><b>🚩 Risk flags:</b> ' + risks.join(', ') + '</p>') : '';
const itemsHtml = items.length ? ('<ul>' + items.map(a => '<li>' + esc(a) + '</li>').join('') + '</ul>') : '<p><i>None</i></p>';
const prodHtml = products.length ? ('<ul>' + products.map(p => '<li>' + esc(p.name) + (p.quantity ? (' &times; ' + p.quantity) : '') + '</li>').join('') + '</ul>') : '<p><i>None specified</i></p>';

const previewHtml =
  bannerHtml + risksHtml + '<hr>' +
  row('Company', esc(data.company_name) || '<i>(missing)</i>') +
  row('Contact', esc(data.contact_name) || '<i>(missing)</i>') +
  row('Confidence', confidence) +
  '<h4>Routing &amp; classification</h4>' +
  row('Customer type', esc(data.customer_type) || '<i>(unknown)</i>') +
  row('Product line', esc(data.product_category) || '<i>(unknown)</i>') +
  row('Territory', esc(data.territory_state) || '<i>(unknown)</i>') +
  row('Project', esc(data.project_name) || '<i>(none)</i>') +
  row('Priority', esc(data.priority) || '<i>(n/a)</i>') +
  '<h4>Summary</h4><div>' + (esc(data.summary) || '<i>(none)</i>') + '</div>' +
  '<h4>Action items</h4>' + itemsHtml +
  '<h4>Order intent</h4>' + row('Present', oi.present ? 'YES' : 'no') + '<b>Products:</b>' + prodHtml +
  row('Timeline', esc(oi.timeline) || '<i>(none)</i>') +
  row('Notes', esc(oi.notes) || '<i>(none)</i>');

return [{ json: {
  extracted: data, missing, confidence, needs_review: needsReview, parse_error: parseError,
  preview, preview_html: previewHtml,
  transcript: norm.transcript, source: norm.source, received_at: norm.received_at
} }];

const form = $input.first().json;
const v = $('Validate & Flag Gaps').first().json;
const ex = v.extracted || {};

const companyOverride = (form['Company name'] || '').toString().trim();
const contactOverride = (form['Contact name'] || '').toString().trim();
const decision = (form['Decision'] || 'Reject').toString();
const notes = (form['Reviewer notes'] || '').toString();
const approved = decision.toLowerCase().indexOf('approve') !== -1;

const company = companyOverride || ex.company_name || null;
const contact = contactOverride || ex.contact_name || null;
const territory = ex.territory_state || 'n/a';
const prio = ex.priority || 'n/a';

let missing = Array.isArray(v.missing) ? v.missing.slice() : [];
if (company) missing = missing.filter(m => m !== 'company_name');
if (contact) missing = missing.filter(m => m !== 'contact_name');

const notifyBody = [
  'A new sales-call opportunity was approved in the CRM.',
  '',
  'Account:       ' + (company || 'Unknown'),
  'Contact:       ' + (contact || 'n/a'),
  'Project:       ' + (ex.project_name || 'n/a'),
  'Territory:     ' + territory,
  'Product line:  ' + (ex.product_category || 'n/a'),
  'Customer type: ' + (ex.customer_type || 'n/a'),
  'Priority:      ' + prio,
  'Risk flags:    ' + ((ex.risk_flags || []).join(', ') || 'none'),
  '',
  'Summary: ' + (ex.summary || ''),
  '',
  'Reviewer notes: ' + (notes || '(none)')
].join('\n');

return [{ json: {
  decision, approved, reviewer_notes: notes,
  notify: {
    subject: 'New opportunity — ' + (company || 'Unknown') + ' (' + territory + ', ' + prio + ' priority)',
    body: notifyBody
  },
  record: {
    company_name: company,
    contact_name: contact,
    summary: ex.summary || null,
    action_items: JSON.stringify(ex.action_items || []),
    order_intent: JSON.stringify(ex.order_intent || {}),
    project_name: ex.project_name || null,
    customer_type: ex.customer_type || null,
    product_category: ex.product_category || null,
    territory_state: ex.territory_state || null,
    priority: ex.priority || null,
    risk_flags: JSON.stringify(ex.risk_flags || []),
    missing_fields: JSON.stringify(missing),
    confidence: v.confidence || 'low',
    status: approved ? 'approved' : 'rejected',
    source: v.source || 'manual',
    raw_transcript: v.transcript || ''
  }
} }];
